import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';
import { ActivityIndicator, Alert, Button, SafeAreaView, StyleSheet, Text, TextInput, View } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AUTH_STORAGE_KEY = '@mvp_auth_state';

const AuthContext = createContext(null);

async function persistAuthState(authState) {
  await AsyncStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(authState));
}

async function loadAuthState() {
  const raw = await AsyncStorage.getItem(AUTH_STORAGE_KEY);
  if (!raw) return null;
  try {
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

async function clearAuthState() {
  await AsyncStorage.removeItem(AUTH_STORAGE_KEY);
}

function fakeLoginApi(email, password) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (!email || !password) {
        reject(new Error('Email and password are required'));
        return;
      }
      if (password.length < 4) {
        reject(new Error('Invalid credentials'));
        return;
      }
      resolve({
        token: `token_${Date.now()}`,
        user: {
          id: String(Date.now()),
          name: email.split('@')[0],
          email,
        },
      });
    }, 800);
  });
}

function AuthProvider({ children }) {
  const [authState, setAuthState] = useState(null);
  const [isBootstrapping, setIsBootstrapping] = useState(true);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    let mounted = true;
    (async () => {
      try {
        const saved = await loadAuthState();
        if (mounted && saved?.token && saved?.user) {
          setAuthState(saved);
        }
      } finally {
        if (mounted) setIsBootstrapping(false);
      }
    })();
    return () => {
      mounted = false;
    };
  }, []);

  const login = async (email, password) => {
    setIsLoading(true);
    try {
      const result = await fakeLoginApi(email, password);
      const nextState = {
        token: result.token,
        user: result.user,
        loggedInAt: Date.now(),
      };
      setAuthState(nextState);
      await persistAuthState(nextState);
    } finally {
      setIsLoading(false);
    }
  };

  const logout = async () => {
    setIsLoading(true);
    try {
      setAuthState(null);
      await clearAuthState();
    } finally {
      setIsLoading(false);
    }
  };

  const value = useMemo(
    () => ({
      authState,
      user: authState?.user ?? null,
      token: authState?.token ?? null,
      isAuthenticated: !!authState?.token,
      isBootstrapping,
      isLoading,
      login,
      logout,
    }),
    [authState, isBootstrapping, isLoading]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
}

function LoginScreen() {
  const { login, isLoading } = useAuth();
  const [email, setEmail] = useState('demo@example.com');
  const [password, setPassword] = useState('1234');

  const onSubmit = async () => {
    try {
      await login(email.trim(), password);
    } catch (e) {
      Alert.alert('Login failed', e.message || 'Unable to login');
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Sign In</Text>
        <TextInput
          style={styles.input}
          value={email}
          onChangeText={setEmail}
          placeholder="Email"
          autoCapitalize="none"
          keyboardType="email-address"
        />
        <TextInput
          style={styles.input}
          value={password}
          onChangeText={setPassword}
          placeholder="Password"
          secureTextEntry
        />
        <Button title={isLoading ? 'Signing in...' : 'Login'} onPress={onSubmit} disabled={isLoading} />
      </View>
    </SafeAreaView>
  );
}

function HomeScreen() {
  const { user, token, logout, isLoading } = useAuth();

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Welcome</Text>
        <Text style={styles.text}>Name: {user?.name}</Text>
        <Text style={styles.text}>Email: {user?.email}</Text>
        <Text style={styles.text} numberOfLines={1}>
          Token: {token}
        </Text>
        <View style={styles.spacer} />
        <Button title={isLoading ? 'Logging out...' : 'Logout'} onPress={logout} disabled={isLoading} />
      </View>
    </SafeAreaView>
  );
}

function AppNavigator() {
  const { isAuthenticated, isBootstrapping } = useAuth();

  if (isBootstrapping) {
    return (
      <SafeAreaView style={styles.center}>
        <ActivityIndicator size="large" />
      </SafeAreaView>
    );
  }

  return isAuthenticated ? <HomeScreen /> : <LoginScreen />;
}

export default function App() {
  return (
    <AuthProvider>
      <AppNavigator />
    </AuthProvider>
  );
}

